int array_count_increasing_steps(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == array_count_increasing_steps_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    for (i = 0; i + 1 < n; ++i) {
        if (a[i] < a[i + 1]) {
            cnt++;
        }
    }

    return cnt;
}

